import redis
from typing import Dict, Any

class RedisService:
    def __init__(self, host: str, port: int, password: str):
        self.host = host
        self.port = port
        self.password = password
        self.redis_client = None

    def connect(self) -> redis.Redis:
        try:
            self.redis_client = redis.Redis(
                host=self.host,
                port=self.port,
                db=0,
                decode_responses=True,
                socket_timeout=None,
                ssl_cert_reqs='required',
                ssl_keyfile='/path/to/your/key.pem',
                ssl_certfile='/path/to/your/cert.pem'
            )
        except redis.ConnectionError as e:
            print(f"Redis connection error: {e}")
            return None
        return self.redis_client

    def store_session_token(self, user_id: str, token: str) -> bool:
        try:
            ttl = 60 * 60 * 24 * 30  # 30 days in seconds
            self.redis_client.set(f"session:{user_id}", token, ex=ttl)
            return True
        except redis.RedisError as e:
            print(f"Redis error: {e}")
            return False

    def store_api_key(self, user_id: str, api_key: str) -> bool:
        try:
            ttl = 60 * 60 * 24 * 30  # 30 days in seconds
            self.redis_client.set(f"api_key:{user_id}", api_key, ex=ttl)
            return True
        except redis.RedisError as e:
            print(f"Redis error: {e}")
            return False

    def get_session_token(self, user_id: str) -> str:
        try:
            token = self.redis_client.get(f"session:{user_id}")
            if token is None:
                return None
            return token.decode('utf-8')
        except redis.RedisError as e:
            print(f"Redis error: {e}")
            return None

    def get_api_key(self, user_id: str) -> str:
        try:
            api_key = self.redis_client.get(f"api_key:{user_id}")
            if api_key is None:
                return None
            return api_key.decode('utf-8')
        except redis.RedisError as e:
            print(f"Redis error: {e}")
            return None

